import { format, isValid, parse as parseDateFns, parseISO } from 'date-fns';
import { formatInTimeZone, zonedTimeToUtc } from 'date-fns-tz';

/* ============================
   ЛОГИКА TIME PICKER = TRUE
   ============================ */

/**
 * Парсим строку "dd.MM.yyyy HH:mm" -> UTC (ISO) с учётом timeZone (IANA).
 * Если timeZone не задан, считаем, что пользователь вводит системное локальное время.
 */
export const parseWithTimeZone = (userInput: string, timeZone?: string): string | null => {
	if (!userInput.trim()) {
		return null;
	}

	// Парсим "dd.MM.yyyy HH:mm" как будто это системное локальное время
	const parsedLocal = parseDateFns(userInput, 'dd.MM.yyyy HH:mm', new Date());
	if (!isValid(parsedLocal)) {
		return null;
	}

	if (!timeZone) {
		// => нет IANA, fallback: считаем parsedLocal в системном поясе
		// parsedLocal уже интерпретируется как локальное время, просто конвертируем в UTC
		return parsedLocal.toISOString();
	}

	// => у нас есть IANA timeZone, например "Europe/Moscow"
	const utcDate = zonedTimeToUtc(parsedLocal, timeZone);
	return utcDate.toISOString();
};

/**
 * Форматируем ISO UTC -> "dd.MM.yyyy HH:mm" с учётом IANA timeZone, если есть,
 * иначе форматируем в системном поясе.
 */
export const formatWithTimeZone = (dateIsoString: string, timeZone?: string): string => {
	if (!dateIsoString) {
		return '';
	}

	const dateObj = parseISO(dateIsoString);
	if (!isValid(dateObj)) {
		return '';
	}

	if (!timeZone) {
		// Нет IANA, значит системный локальный пояс
		// date-fns автоматически конвертирует UTC в локальное время
		return format(dateObj, 'dd.MM.yyyy HH:mm');
	}

	// Имеем IANA, используем date-fns-tz
	return formatInTimeZone(dateObj, timeZone, 'dd.MM.yyyy HH:mm');
};

/* ==============================
   ЛОГИКА TIME PICKER = FALSE
   ============================== */

/**
 * Парсит "dd.MM.yyyy" -> "yyyy-MM-dd"
 * (не учитываем часовые пояса)
 */
export const parseDateOnly = (userInput: string): string | null => {
	if (!userInput.trim()) {
		return null;
	}
	const parsed = parseDateFns(userInput, 'dd.MM.yyyy', new Date());
	if (!isValid(parsed)) {
		return null;
	}
	return format(parsed, 'yyyy-MM-dd');
};

/**
 * Форматируем "yyyy-MM-dd" (или ISO c T) -> "dd.MM.yyyy"
 * Если есть T, берём только дату (без времени).
 */
export const formatDateOnly = (value: string): string => {
	if (!value) {
		return '';
	}
	if (value.includes('T')) {
		// допустим, "2025-02-08T15:06:00Z"
		const d = parseISO(value);
		if (!isValid(d)) {
			return '';
		}
		return format(d, 'dd.MM.yyyy');
	}
	const parsed = parseDateFns(value, 'yyyy-MM-dd', new Date());
	if (!isValid(parsed)) {
		return '';
	}
	return format(parsed, 'dd.MM.yyyy');
};

/**
 * Если приходит полная ISO, берём только yyyy-MM-dd
 */
export const normalizeDateValue = (value: string): string => {
	if (!value) {
		return '';
	}
	if (value.includes('T')) {
		const d = parseISO(value);
		if (!isValid(d)) {
			return '';
		}
		return format(d, 'yyyy-MM-dd');
	}
	return value;
};
